import (
	"encoding/json"
	"errors"
	"os"
	"sort"
)

type entry struct {
	Case      string `json:"case"`
	Produced  []int  `json:"produced"`
	Trace     []int  `json:"slot_trace"`
	OrderUsed []int  `json:"order_used"`
	Packed    bool   `json:"packed"`
	Grouped   bool   `json:"grouped"`
	Reuse     bool   `json:"reuse"`
}

type rawDoc struct {
	Raw []entry `json:"raw"`
}

type finalDoc struct {
	Rows    []entry        `json:"rows"`
	Summary map[string]any `json:"summary"`
}

func indexByCase(a []entry) map[string]entry {
	m := make(map[string]entry, len(a))
	for _, r := range a {
		m[r.Case] = r
	}
	return m
}

func equalRow(a, b entry) bool {
	if a.Case != b.Case || a.Packed != b.Packed || a.Grouped != b.Grouped || a.Reuse != b.Reuse {
		return false
	}
	if len(a.Produced) != len(b.Produced) || len(a.Trace) != len(b.Trace) || len(a.OrderUsed) != len(b.OrderUsed) {
		return false
	}
	for i := range a.Produced {
		if a.Produced[i] != b.Produced[i] {
			return false
		}
	}
	for i := range a.Trace {
		if a.Trace[i] != b.Trace[i] {
			return false
		}
	}
	for i := range a.OrderUsed {
		if a.OrderUsed[i] != b.OrderUsed[i] {
			return false
		}
	}
	return true
}

func loadFinal(path string) (finalDoc, error) {
	var doc finalDoc
	buf, err := os.ReadFile(path)
	if err != nil {
		return doc, err
	}
	if err := json.Unmarshal(buf, &doc); err != nil {
		return doc, err
	}
	return doc, nil
}

func main() {
	if len(os.Args) != 3 {
		panic("usage: align raw final")
	}
	rawPath := os.Args[1]
	finalPath := os.Args[2]

	buf, err := os.ReadFile(rawPath)
	if err != nil {
		panic(err)
	}
	var raw rawDoc
	if err := json.Unmarshal(buf, &raw); err != nil {
		panic(err)
	}

	// One report row per raw row; deterministic ordering.
	rows := make([]entry, 0, len(raw.Raw))
	rows = append(rows, raw.Raw...)
	sort.Slice(rows, func(i, j int) bool { return rows[i].Case < rows[j].Case })

	rawByCase := indexByCase(raw.Raw)

	agree := true

	// If overwriting an existing report.json, compare *prior* report rows
	// against incoming raw rows across: produced, slot_trace, order_used,
	// packed, grouped, reuse (keyed by case name).
	if prior, err := loadFinal(finalPath); err == nil {
		priorByCase := indexByCase(prior.Rows)
		if len(priorByCase) != len(rawByCase) {
			agree = false
		} else {
			for k, r := range rawByCase {
				p, ok := priorByCase[k]
				if !ok || !equalRow(r, p) {
					agree = false
					break
				}
			}
		}
	} else if !errors.Is(err, os.ErrNotExist) {
		panic(err)
	}

	// Also require newly written report rows match incoming raw rows.
	if len(rows) != len(raw.Raw) {
		agree = false
	} else {
		for _, rr := range rows {
			r, ok := rawByCase[rr.Case]
			if !ok || !equalRow(r, rr) {
				agree = false
				break
			}
		}
	}

	doc := finalDoc{Rows: rows, Summary: map[string]any{"total": len(raw.Raw), "agree": agree}}
	out, err := json.MarshalIndent(doc, "", "  ")
	if err != nil {
		panic(err)
	}
	if err := os.WriteFile(finalPath, append(out, '\n'), 0o644); err != nil {
		panic(err)
	}
}
